        uint256 newRewards = nanocore.balanceOf(address(this)).sub(nanocoreBalance);

        if(newRewards > 0) {
            nanocoreBalance = nanocore.balanceOf(address(this)); // If there is no change the balance didn't change
            pendingRewards = pendingRewards.add(newRewards);
            rewardsInThisEpoch = rewardsInThisEpoch.add(newRewards);
        }
